const items = $input.all();

const results = [];

for (const item of items) {

  const alerts = item.json.body.alerts;

  if (!alerts || alerts.length === 0) {
    continue;
  }

  for (const alert of alerts) {

    const health = alert.health_percent;

    let anomaly_probability;
    let issue;
    let severity;

    if (health <= 25) {
      anomaly_probability = 99.9;
      issue = "Severe mechanical degradation detected";
      severity = "CRITICAL";
    } 
    else if (health <= 50) {
      anomaly_probability = 75.0;
      issue = "Performance degradation detected";
      severity = "HIGH";
    } 
    else if (health <= 75) {
      anomaly_probability = 40.0;
      issue = "Early wear trend observed";
      severity = "MEDIUM";
    } 
    else {
      anomaly_probability = 10.0;
      issue = "Normal operational condition";
      severity = "LOW";
    }

    results.push({
      json: {
        ...alert,
        robot_id: item.json.body.robot_id,
        timestamp: item.json.body.timestamp,
        anomaly_probability,
        issue,
        severity
      }
    });
  }
}

return results;

